import{_ as a,o as t,c as o,an as i}from"./chunks/framework.CjbmvEPf.js";const p=JSON.parse('{"title":"Release notes","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes.md","filePath":"release-notes.md","lastUpdated":null}'),r={name:"release-notes.md"};function s(d,e,n,l,c,u){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="Release-notes" tabindex="-1">Release notes <a class="header-anchor" href="#Release-notes" aria-label="Permalink to &quot;Release notes {#Release-notes}&quot;">​</a></h1><p>ModifiedDistributions.jl follows a hybrid changelog approach:</p><ul><li><p><strong>GitHub Releases</strong>: All releases (automatically generated by TagBot)</p></li><li><p><strong>NEWS.md</strong>: Major releases requiring detailed context (shown below)</p></li></ul><p>See <a href="https://github.com/EpiAware/ModifiedDistributions.jl/releases" target="_blank" rel="noreferrer">GitHub Releases</a> for minor/patch release information.</p><h2 id="Unreleased" tabindex="-1">Unreleased <a class="header-anchor" href="#Unreleased" aria-label="Permalink to &quot;Unreleased {#Unreleased}&quot;">​</a></h2><p>This file tracks notes for major releases and significant milestones; GitHub Releases (auto-generated from merged PRs) cover every release in between.</p><h3 id="Features" tabindex="-1">Features <a class="header-anchor" href="#Features" aria-label="Permalink to &quot;Features {#Features}&quot;">​</a></h3><ul><li><p>Ported the <code>Affine</code> modifier from CensoredDistributions.jl: <code>affine(dist; scale, shift)</code> gives the exact change-of-variables distribution of <code>scale * X + shift</code>, including tail-accurate <code>ccdf</code>/<code>logccdf</code>, summary statistics, and discrete-support handling (#10, #13).</p></li><li><p>Ported the <code>Weighted</code> modifier: <code>weight(dist, w)</code> scales <code>logpdf</code> by a weight for aggregated or count observations, with observation-time weights, vectorised <code>Product</code> forms, and delegated summary statistics (#10, #13).</p></li><li><p>Ported the <code>Transformed</code> forward-series modifier with <code>thin</code>/<code>cumulative</code>/<code>transform</code>, transparent to every distribution method (#10).</p></li><li><p>Added the generic <code>get_dist</code>/<code>get_dist_recursive</code> unwrap protocol, extendable by downstream wrapper packages (#10).</p></li><li><p>Added the <code>modify</code> hazard-modification verb: <code>Modified</code> transforms a continuous distribution&#39;s hazard through a link, with closed-form proportional-hazards (<code>log</code>, default) and additive-hazards (<code>identity</code>, non-negative effects, hazard accrued from the support minimum) paths. General links, negative additive effects, and the discrete path stay upstream in CensoredDistributions.jl (#12, #17).</p></li><li><p>Added a ComposedDistributions.jl package extension letting the modifier verbs apply across a composed <code>Sequential</code> chain by modifying its observed scalar (#14).</p></li></ul><h3 id="Documentation" tabindex="-1">Documentation <a class="header-anchor" href="#Documentation" aria-label="Permalink to &quot;Documentation {#Documentation}&quot;">​</a></h3><ul><li>Getting-started overview touring every modifier, an FAQ, a guide to writing new modifiers, an extended README, and a package logo (#19).</li></ul><h2 id="v0.1.0-Initial-release" tabindex="-1">v0.1.0 - Initial release <a class="header-anchor" href="#v0.1.0-Initial-release" aria-label="Permalink to &quot;v0.1.0 - Initial release {#v0.1.0-Initial-release}&quot;">​</a></h2><p>Package scaffolded with EpiAwarePackageTools (managed CI, DocumenterVitepress docs, Aqua/ExplicitImports/JET quality gates, and the multi-backend AD test harness) (#9).</p>',12)])])}const m=a(r,[["render",s]]);export{p as __pageData,m as default};
